SELECT
ID,
INVOICE_QUERY_ID,
NATURE_LINES,
ITEM,
SHORTER_ITEM,
SPECIFICATION,
MEASUREMENT_DIMENSION,
QUANTITY,
PRICE,
AMOUNT,
TAX_SCHEME,
TAX_AMOUNT,
PRODUCT_CODE,
SELF_PRODUCT_CODE,
ZEROTAX_SCHEME_MARK,
BLUE_LETTER_INVOICE_ID,
CREATE_BY,
CREATE_BY_NAME,
CREATE_TIME,
UPDATE_BY,
UPDATE_BY_NAME,
UPDATE_TIME
FROM
T_SD_INVOICE_QUERY_ITEM


        and ID = #{id}


        and INVOICE_QUERY_ID = #{invoiceQueryId}


        and NATURE_LINES = #{natureLines}


        and ITEM = #{item}


        and SHORTER_ITEM = #{shorterItem}


        and SPECIFICATION = #{specification}


        and MEASUREMENT_DIMENSION = #{measurementDimension}


        and QUANTITY = #{quantity}


        and PRICE = #{price}


        and AMOUNT = #{amount}


        and TAX_SCHEME = #{taxScheme}


        and TAX_AMOUNT = #{taxAmount}


        and PRODUCT_CODE = #{productCode}


        and SELF_PRODUCT_CODE = #{selfProductCode}


        and ZEROTAX_SCHEME_MARK = #{zerotaxSchemeMark}


        and BLUE_LETTER_INVOICE_ID = #{blueLetterInvoiceId}
